import React, { useState } from 'react';

const SignupLogin: React.FC = () => {
    const [isLogin, setIsLogin] = useState(true);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        // Handle signup or login logic here
    };

    return (
        <div 
            className="flex flex-col items-center justify-center min-h-screen"
            style={{
                background: 'linear-gradient(135deg, #fceabb 0%, #f8b500 100%)', // Pastel gradient
            }}
        >
            <h1 className="text-3xl font-bold mb-6 text-gray-800">
                {isLogin ? 'Login' : 'Sign Up'}
            </h1>
            <form 
                onSubmit={handleSubmit} 
                className="bg-white p-6 rounded-2xl shadow-lg w-80"
                style={{
                    backgroundColor: 'rgba(255, 255, 255, 0.9)',
                }}
            >
                <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">Email</label>
                    <input
                        type="email"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        required
                        className="mt-1 block w-full border border-gray-300 rounded-md p-2 focus:ring-2 focus:ring-pink-300"
                    />
                </div>
                <div className="mb-4">
                    <label className="block text-sm font-medium text-gray-700">Password</label>
                    <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        required
                        className="mt-1 block w-full border border-gray-300 rounded-md p-2 focus:ring-2 focus:ring-pink-300"
                    />
                </div>
                <button
                    type="submit"
                    className="w-full bg-pink-400 text-white py-2 rounded-md hover:bg-pink-500 transition duration-300"
                >
                    {isLogin ? 'Login' : 'Sign Up'}
                </button>
                <p className="mt-4 text-sm text-center text-gray-700">
                    {isLogin ? 'Don’t have an account?' : 'Already have an account?'}
                    <button
                        type="button"
                        onClick={() => setIsLogin(!isLogin)}
                        className="text-pink-500 ml-1 hover:underline"
                    >
                        {isLogin ? 'Sign Up' : 'Login'}
                    </button>
                </p>
            </form>
        </div>
    );
};

export default SignupLogin;
